{"command":"$repos = Get-ChildItem -Directory | Where-Object { Test-Path (Join-Path $_.FullName '.git') }
foreach ($repo in $repos) {
  Write-Output "[$($repo.Name)]"
  git -C $repo.FullName fetch origin --prune
}","workdir":"D:\repos\dflow","timeout_ms":120000}

{"command":"$repos = Get-ChildItem -Directory | Where-Object { Test-Path (Join-Path $_.FullName '.git') }
foreach ($repo in $repos) {
  $path = $repo.FullName
  $hasDevelop = git -C $path rev-parse --verify --quiet origin/develop
  $hasSandbox = git -C $path rev-parse --verify --quiet origin/sandbox-albert
  Write-Output "[$($repo.Name)]"
  if (-not $hasDevelop) { Write-Output "missing origin/develop"; continue }
  if (-not $hasSandbox) { Write-Output "missing origin/sandbox-albert"; continue }
  $counts = git -C $path rev-list --left-right --count origin/sandbox-albert...origin/develop
  $mergeBase = git -C $path merge-base origin/sandbox-albert origin/develop
  $sandbox = git -C $path rev-parse origin/sandbox-albert
  $develop = git -C $path rev-parse origin/develop
  Write-Output "sandbox...develop counts: $counts"
  Write-Output "sandbox: $($sandbox.Substring(0,12)) develop: $($develop.Substring(0,12)) base: $($mergeBase.Substring(0,12))"
}","workdir":"D:\repos\dflow","timeout_ms":120000}

{"command":"$repos = Get-ChildItem -Directory | Where-Object { Test-Path (Join-Path $_.FullName '.git') }
foreach ($repo in $repos) {
  $path = $repo.FullName
  Write-Output "[$($repo.Name)]"
  $branch = git -C $path branch --show-current
  $status = git -C $path status --porcelain
  $counts = git -C $path rev-list --left-right --count HEAD...origin/sandbox-albert
  Write-Output "branch: $branch local...origin/sandbox-albert: $counts dirty: $([bool]$status)"
}","workdir":"D:\repos\dflow","timeout_ms":120000}

{"command":"$repos = Get-ChildItem -Directory | Where-Object { Test-Path (Join-Path $_.FullName '.git') }
foreach ($repo in $repos) {
  Write-Output "[$($repo.Name)]"
  git -C $repo.FullName merge --ff-only origin/sandbox-albert
}","workdir":"D:\repos\dflow","timeout_ms":120000}

