function firstNumber(...values) {
  for (const value of values) {
    if (typeof value === 'number' && Number.isFinite(value)) return value;
  }
  return undefined;
}

function sumObjectNumbers(value) {
  if (!value || typeof value !== 'object') return 0;
  return Object.values(value).reduce((sum, n) => (
    typeof n === 'number' && Number.isFinite(n) ? sum + n : sum
  ), 0);
}

function normaliseUsage(usage) {
  if (!usage) return usage;

  const promptTokens = firstNumber(usage.prompt_tokens, usage.input_tokens) ?? 0;
  const completionTokens = firstNumber(usage.completion_tokens, usage.output_tokens) ?? 0;
  const totalTokens = firstNumber(usage.total_tokens) ?? (promptTokens + completionTokens);
  const promptDetails = usage.prompt_tokens_details || usage.input_tokens_details || {};

  const hitTokens = firstNumber(
    usage.prompt_cache_hit_tokens,
    promptDetails.cached_tokens,
    promptDetails.cache_read_tokens,
    usage.cached_tokens,
    usage.cache_read_tokens,
  ) ?? 0;

  const creationTokens = firstNumber(
    usage.prompt_cache_creation_tokens,
    usage.prompt_cache_write_tokens,
    promptDetails.cache_creation_input_tokens,
    promptDetails.cache_write_tokens,
    usage.cache_creation_input_tokens,
    usage.cache_write_tokens,
  ) ?? sumObjectNumbers(promptDetails.cache_creation);

  const missTokens = firstNumber(
    usage.prompt_cache_miss_tokens,
  ) ?? Math.max(promptTokens - hitTokens - creationTokens, 0);

  const hasCacheTelemetry = Boolean(
    hitTokens ||
    creationTokens ||
    usage.prompt_cache_hit_tokens != null ||
    usage.prompt_cache_miss_tokens != null ||
    promptDetails.cached_tokens != null ||
    promptDetails.cache_write_tokens != null ||
    promptDetails.cache_creation_input_tokens != null ||
    usage.cached_tokens != null
  );

  const hitRate = promptTokens > 0 ? hitTokens / promptTokens : 0;

  return {
    ...usage,
    prompt_tokens: promptTokens,
    completion_tokens: completionTokens,
    total_tokens: totalTokens,
    prompt_cache_hit_tokens: hitTokens,
    prompt_cache_miss_tokens: missTokens,
    prompt_cache_creation_tokens: creationTokens,
    prompt_cache_hit_rate: hitRate,
    prompt_cache_hit_rate_pct: Math.round(hitRate * 1000) / 10,
    prompt_cache_telemetry_available: hasCacheTelemetry,
    cache_stats: {
      prompt_tokens: promptTokens,
      hit_tokens: hitTokens,
      miss_tokens: missTokens,
      creation_tokens: creationTokens,
      hit_rate: hitRate,
      hit_rate_pct: Math.round(hitRate * 1000) / 10,
      telemetry_available: hasCacheTelemetry,
    },
  };
}

function logCacheMetrics(provider, model, usage) {
  if (!usage) return;
  const normalized = normaliseUsage(usage);
  const hit = normalized.prompt_cache_hit_tokens || 0;
  const miss = normalized.prompt_cache_miss_tokens || 0;
  const created = normalized.prompt_cache_creation_tokens || 0;
  const comp = normalized.completion_tokens || 0;
  const prompt = normalized.prompt_tokens || 0;
  const hitPct = normalized.prompt_cache_hit_rate_pct || 0;
  const telemetry = normalized.prompt_cache_telemetry_available ? 'reported' : 'unreported';

  console.log(
    `[${provider}] model=${model} ` +
    `prompt=${prompt} cache_hit=${hit} cache_miss=${miss} ` +
    `cache_write=${created} completion=${comp} hit_rate=${hitPct}% ` +
    `cache_telemetry=${telemetry}`
  );
}

module.exports = {
  normaliseUsage,
  logCacheMetrics,
};

