/**
 * Split a stored duty-rate value into the three breakdown components.
 * Accepts shapes: "5.3+25+10", "5.3+25", "40.3", number, null.
 * Anything that doesn't parse as a 1–3 term plain sum goes entirely into MFN.
 */
export function splitDutyRateEquation(input: unknown): { mfn: string; s301: string; trump: string } {
  const empty = { mfn: '', s301: '', trump: '' };
  if (input == null) return empty;
  const raw = String(input).trim();
  if (!raw) return empty;

  // Strict 1–3 term ad valorem decomposition. Reject if anything other than
  // numbers and '+' separators is present so we never silently drop operators.
  if (!/^[\d.+\s]+$/.test(raw)) return { mfn: raw, s301: '', trump: '' };
  const parts = raw.split('+').map(p => p.trim()).filter(p => p.length > 0);
  if (parts.length === 1) return { mfn: parts[0], s301: '', trump: '' };
  if (parts.length === 2) return { mfn: parts[0], s301: parts[1], trump: '' };
  if (parts.length === 3) return { mfn: parts[0], s301: parts[1], trump: parts[2] };
  return { mfn: raw, s301: '', trump: '' };
}

/**
 * Build the equation string stored on the row. Empty components are skipped so
 * the result reads naturally in the cell editor ("5.3+25" not "5.3++25").
 */
export function buildDutyRateEquation(mfn: number, s301: number, trump: number): string {
  const terms: string[] = [];
  if (mfn   > 0 || (mfn   === 0 && s301 === 0 && trump === 0)) terms.push(String(mfn));
  if (s301  > 0) terms.push(String(s301));
  if (trump > 0) terms.push(String(trump));
  return terms.join('+') || '0';
}

