const STRATEGIES = {
  AUTOMATIC_PREFIX: 'automatic-prefix',
  EXPLICIT_CACHE_CONTROL: 'explicit-cache-control',
  SESSION_CACHE: 'session-cache',
  NONE_UNKNOWN: 'none/unknown',
};

function strategyForOpenRouterModel(modelId = '') {
  if (modelId.startsWith('openai/')) return STRATEGIES.AUTOMATIC_PREFIX;
  if (
    modelId.startsWith('anthropic/') ||
    modelId.startsWith('deepseek/') ||
    modelId.startsWith('google/') ||
    modelId.startsWith('qwen/')
  ) {
    return STRATEGIES.EXPLICIT_CACHE_CONTROL;
  }
  return STRATEGIES.NONE_UNKNOWN;
}

function cacheMetadata(strategy, overrides = {}) {
  const base = {
    cache_strategy: strategy,
    cache_eligible: strategy !== STRATEGIES.NONE_UNKNOWN,
    cache_telemetry: strategy === STRATEGIES.NONE_UNKNOWN ? 'unknown' : 'reported-when-provider-returns-usage',
  };

  if (strategy === STRATEGIES.AUTOMATIC_PREFIX) {
    return {
      ...base,
      cache_description: 'Automatic provider prefix caching; repeated stable prompt prefixes can be cached without markers.',
      cache_min_prompt_tokens: 1024,
      ...overrides,
    };
  }

  if (strategy === STRATEGIES.EXPLICIT_CACHE_CONTROL) {
    return {
      ...base,
      cache_description: 'Explicit cache_control breakpoints on the stable system prompt and conversation prefix.',
      cache_ttl_seconds: 300,
      cache_min_prompt_tokens: 1024,
      ...overrides,
    };
  }

  if (strategy === STRATEGIES.SESSION_CACHE) {
    return {
      ...base,
      cache_description: 'Alibaba session cache via Responses API previous_response_id and x-dashscope-session-cache.',
      cache_ttl_seconds: 300,
      cache_min_prompt_tokens: 1024,
      requires_session_id: true,
      ...overrides,
    };
  }

  return {
    ...base,
    cache_description: 'No provider-specific caching strategy is configured for this model.',
    ...overrides,
  };
}

function annotateModel(model) {
  if (!model || model.cache_strategy) return model;
  return {
    ...model,
    ...cacheMetadata(strategyForOpenRouterModel(model.id)),
  };
}

function shouldUseCacheControl(modelId = '') {
  return strategyForOpenRouterModel(modelId) === STRATEGIES.EXPLICIT_CACHE_CONTROL;
}

module.exports = {
  STRATEGIES,
  annotateModel,
  cacheMetadata,
  shouldUseCacheControl,
  strategyForOpenRouterModel,
};

