    return this.selectedModel?.cache_eligible ? 'cache-validation--ok' : 'cache-validation--warn';
  }

  get cacheValidationIcon(): string {
    return this.selectedModel?.cache_eligible ? 'check_circle' : 'warning';
  }

  get cacheValidationText(): string {
    const model = this.selectedModel;
    if (!model) return '';
    if (!model.cache_eligible || model.cache_strategy === 'none/unknown') {
      return 'No provider-specific cache strategy is configured for this model. Expect normal input-token billing unless the provider applies caching silently.';
    }
    if (model.cache_strategy === 'automatic-prefix') {
      return `Eligible when repeated prompt prefixes are stable${model.cache_min_prompt_tokens ? ` and at least ${model.cache_min_prompt_tokens.toLocaleString()} tokens` : ''}. No cache markers are sent.`;
    }
    if (model.cache_strategy === 'explicit-cache-control') {
      return `Eligible through cache_control breakpoints${model.cache_ttl_seconds ? ` with about ${Math.round(model.cache_ttl_seconds / 60)} min TTL` : ''}. Stable system prompt and conversation prefix are marked.`;
    }
    if (model.cache_strategy === 'session-cache') {
      return 'Eligible in RFQ AI sessions through Alibaba Responses API, previous_response_id, and x-dashscope-session-cache. One-off calls fall back to explicit cache markers.';
    }
    return model.cache_description ?? '';
  }

  async save() {
    if (!this.selectedModelId) { return; }
    this.saving = true;
    try {
      await Promise.all([
        firstValueFrom(this.aiSettings.saveApi(this.selectedApi)),
        firstValueFrom(this.aiSettings.saveModel(this.selectedModelId)),
        firstValueFrom(this.aiSettings.saveReasoningEffort(this.selectedEffort)),
      ]);
      this.snackbar.open('AI settings saved', 'OK', { duration: 2000 });
    } catch (err: any) {
      this.snackbar.open(`Save failed: ${err?.message ?? 'Unknown error'}`, 'OK', { duration: 4000 });
    } finally {
      this.saving = false;
    }
  }
}

