/** Sum two ChatUsage objects (cache fields use 0 when absent). */
function addUsage(a: ChatUsage | null | undefined, b: ChatUsage | null | undefined): ChatUsage | null {
  if (!a) return b ?? null;
  if (!b) return a;
  const prompt = (a.prompt_tokens || 0) + (b.prompt_tokens || 0);
  const hit = (a.prompt_cache_hit_tokens || 0) + (b.prompt_cache_hit_tokens || 0);
  const created = (a.prompt_cache_creation_tokens || 0) + (b.prompt_cache_creation_tokens || 0);
  const miss = (a.prompt_cache_miss_tokens || 0) + (b.prompt_cache_miss_tokens || 0);
  const hitRate = prompt > 0 ? hit / prompt : 0;
  return {
